public boolean canSplitString(String s) {
    int[] count = new int[10];
    for (char c : s.toCharArray()) {
        count[c - '0']++;
    }

    for (int i = 1; i <= 9; i++) {
        if (count[i] > 0 && count[i] == count[i - 1]) {
            return true;
        }
    }
    return false;
}
